import React, { useRef, useEffect } from 'react';
import { usePlayer } from '../context/PlayerContext';
import { FaPlay, FaPause, FaStepForward, FaStepBackward } from 'react-icons/fa';

const Player = () => {
  const { currentSong, isPlaying, setIsPlaying, togglePlay } = usePlayer();
  const audioRef = useRef(null);

  useEffect(() => {
    if (currentSong && audioRef.current) {
      if (isPlaying) {
        audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  }, [currentSong, isPlaying]);

  if (!currentSong) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-gray-900 text-white h-20 border-t border-gray-700 flex items-center px-4 z-50">
      {/* Audio Element ẩn */}
      <audio 
        ref={audioRef} 
        src={currentSong.audioUrl} 
        onEnded={() => setIsPlaying(false)}
      />

      {/* Info */}
      <div className="w-1/4 flex items-center gap-3">
        <img src={currentSong.coverImage || 'https://via.placeholder.com/50'} alt="cover" className="w-12 h-12 object-cover rounded" />
        <div className="truncate">
          <h4 className="text-sm font-bold">{currentSong.title}</h4>
          <p className="text-xs text-gray-400">{currentSong.artist}</p>
        </div>
      </div>

      {/* Controls */}
      <div className="flex-1 flex flex-col items-center justify-center">
        <div className="flex items-center gap-6 mb-1">
          <button className="text-gray-400 hover:text-white"><FaStepBackward /></button>
          <button 
            onClick={togglePlay}
            className="w-10 h-10 rounded-full bg-orange-500 flex items-center justify-center hover:scale-105 transition"
          >
            {isPlaying ? <FaPause /> : <FaPlay className="ml-1" />}
          </button>
          <button className="text-gray-400 hover:text-white"><FaStepForward /></button>
        </div>
        {/* Progress Bar (Simple version) */}
        <div className="w-full max-w-md h-1 bg-gray-600 rounded cursor-pointer relative group">
            <div className="absolute top-0 left-0 h-full bg-orange-500 w-1/3"></div>
        </div>
      </div>

      {/* Volume / Extra */}
      <div className="w-1/4 flex justify-end">
        {/* Volume control placeholder */}
        <span className="text-xs text-gray-400">Volume</span>
      </div>
    </div>
  );
};

export default Player;
